diff --git a/test/prependData-option.test.js b/test/prependData-option.test.js
new file mode 100644
index 0000000..3e36160
--- /dev/null
+++ b/test/prependData-option.test.js
@@ -0,0 +1,62 @@
+/**
+ * @jest-environment node
+ */
+import nodeSass from 'node-sass';
+import dartSass from 'sass';
+
+import {
+  compile,
+  getTestId,
+  getCodeFromBundle,
+  getCodeFromSass,
+  getImplementationByName,
+} from './helpers';
+
+const implementations = [nodeSass, dartSass];
+const syntaxStyles = ['scss', 'sass'];
+
+describe('prependData option', () => {
+  implementations.forEach((implementation) => {
+    const [implementationName] = implementation.info.split('\t');
+
+    syntaxStyles.forEach((syntax) => {
+      it(`should work with the "data" option as a string (${implementationName}) (${syntax})`, async () => {
+        const testId = getTestId('prepending-data', syntax);
+        const options = {
+          implementation: getImplementationByName(implementationName),
+          prependData: `$prepended-data: hotpink${
+            syntax === 'sass' ? '\n' : ';'
+          }`,
+        };
+        const stats = await compile(testId, { loader: { options } });
+
+        expect(getCodeFromBundle(stats).css).toBe(
+          getCodeFromSass(testId, options).css
+        );
+
+        expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+        expect(stats.compilation.errors).toMatchSnapshot('errors');
+      });
+
+      it(`should work with the "data" option as a function (${implementationName}) (${syntax})`, async () => {
+        const testId = getTestId('prepending-data', syntax);
+        const options = {
+          implementation: getImplementationByName(implementationName),
+          prependData: (loaderContext) => {
+            expect(loaderContext).toBeDefined();
+
+            return `$prepended-data: hotpink${syntax === 'sass' ? '\n' : ';'}`;
+          },
+        };
+        const stats = await compile(testId, { loader: { options } });
+
+        expect(getCodeFromBundle(stats).css).toBe(
+          getCodeFromSass(testId, options).css
+        );
+
+        expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+        expect(stats.compilation.errors).toMatchSnapshot('errors');
+      });
+    });
+  });
+});

diff --git a/test/sassOptions-option.test.js b/test/sassOptions-option.test.js
new file mode 100644
index 0000000..2b5d0c6
--- /dev/null
+++ b/test/sassOptions-option.test.js
@@ -0,0 +1,124 @@
+/**
+ * @jest-environment node
+ */
+import path from 'path';
+
+import nodeSass from 'node-sass';
+import dartSass from 'sass';
+
+import {
+  compile,
+  getTestId,
+  getCodeFromBundle,
+  getCodeFromSass,
+  getImplementationByName,
+} from './helpers';
+import customImporter from './helpers/customImporter';
+import customFunctions from './helpers/customFunctions';
+
+const implementations = [nodeSass, dartSass];
+const syntaxStyles = ['scss', 'sass'];
+
+describe('sassOptions option', () => {
+  implementations.forEach((implementation) => {
+    const [implementationName] = implementation.info.split('\t');
+
+    syntaxStyles.forEach((syntax) => {
+      it(`should work when the option like "Object" (${implementationName}) (${syntax})`, async () => {
+        const testId = getTestId('language', syntax);
+        const options = {
+          implementation: getImplementationByName(implementationName),
+          sassOptions: {
+            indentWidth: 10,
+          },
+        };
+        const stats = await compile(testId, { loader: { options } });
+
+        expect(getCodeFromBundle(stats).css).toBe(
+          getCodeFromSass(testId, options).css
+        );
+
+        expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+        expect(stats.compilation.errors).toMatchSnapshot('errors');
+      });
+
+      it(`should work when the option like "Function" (${implementationName}) (${syntax})`, async () => {
+        expect.assertions(5);
+
+        const testId = getTestId('language', syntax);
+        const options = {
+          implementation: getImplementationByName(implementationName),
+          sassOptions: (loaderContext) => {
+            expect(loaderContext).toBeDefined();
+
+            return {
+              indentWidth: 10,
+            };
+          },
+        };
+        const stats = await compile(testId, { loader: { options } });
+
+        expect(getCodeFromBundle(stats).css).toBe(
+          getCodeFromSass(testId, options).css
+        );
+
+        expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+        expect(stats.compilation.errors).toMatchSnapshot('errors');
+      });
+
+      it(`should work with the "importer" option (${implementationName}) (${syntax})`, async () => {
+        const testId = getTestId('custom-importer', syntax);
+        const options = {
+          implementation: getImplementationByName(implementationName),
+          sassOptions: {
+            importer: customImporter,
+          },
+        };
+        const stats = await compile(testId, { loader: { options } });
+
+        expect(getCodeFromBundle(stats).css).toBe(
+          getCodeFromSass(testId, options).css
+        );
+
+        expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+        expect(stats.compilation.errors).toMatchSnapshot('errors');
+      });
+
+      it(`should work with the "functions" option (${implementationName}) (${syntax})`, async () => {
+        const testId = getTestId('custom-functions', syntax);
+        const options = {
+          implementation: getImplementationByName(implementationName),
+          sassOptions: {
+            functions: customFunctions(implementation),
+          },
+        };
+        const stats = await compile(testId, { loader: { options } });
+
+        expect(getCodeFromBundle(stats).css).toBe(
+          getCodeFromSass(testId, options).css
+        );
+
